from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import os
import re
import time
import secrets

app = Flask(__name__)

w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
NONCES = {}

ADDRESS_RE = re.compile(r"^0x[a-fA-F0-9]{40}$")


def normalize_address(address: str) -> str:
    if not isinstance(address, str) or not ADDRESS_RE.match(address):
        raise ValueError("Invalid Ethereum address")
    return Web3.to_checksum_address(address)


def cleanup_nonces():
    now = time.time()
    expired = [nonce for nonce, data in NONCES.items() if now - data["created_at"] > NONCE_TTL_SECONDS]
    for nonce in expired:
        NONCES.pop(nonce, None)


def generate_nonce(address: str) -> str:
    cleanup_nonces()
    nonce = secrets.token_urlsafe(32)
    NONCES[nonce] = {
        "address": normalize_address(address),
        "created_at": time.time(),
        "used": False,
    }
    return nonce


def verify_signature(address: str, message: str, signature: str) -> bool:
    try:
        checksum_address = normalize_address(address)
        if not isinstance(message, str) or not message:
            return False
        if not isinstance(signature, str) or not signature.startswith("0x"):
            return False

        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(encoded_message, signature=signature)
        return Web3.to_checksum_address(recovered_address) == checksum_address
    except Exception:
        return False


@app.route("/nonce", methods=["POST"])
def nonce():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    try:
        nonce = generate_nonce(address)
        message = f"Sign this message to authenticate.\n\nAddress: {normalize_address(address)}\nNonce: {nonce}\nIssued At: {int(time.time())}"
        NONCES[nonce]["message"] = message
        return jsonify({"nonce": nonce, "message": message}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 400


@app.route("/authenticate", methods=["POST"])
def authenticate():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    message = data.get("message")
    signature = data.get("signature")

    if not all([address, message, signature]):
        return jsonify({"authenticated": False, "error": "Missing required fields"}), 400

    try:
        checksum_address = normalize_address(address)
    except Exception as e:
        return jsonify({"authenticated": False, "error": str(e)}), 400

    nonce = None
    for n, info in NONCES.items():
        if info.get("message") == message and info.get("address") == checksum_address:
            nonce = n
            break

    if nonce is None:
        return jsonify({"authenticated": False, "error": "Unknown or expired nonce"}), 401

    nonce_info = NONCES.get(nonce)
    if not nonce_info or nonce_info.get("used"):
        return jsonify({"authenticated": False, "error": "Nonce already used"}), 401

    if time.time() - nonce_info["created_at"] > NONCE_TTL_SECONDS:
        NONCES.pop(nonce, None)
        return jsonify({"authenticated": False, "error": "Nonce expired"}), 401

    if not verify_signature(checksum_address, message, signature):
        return jsonify({"authenticated": False, "error": "Invalid signature"}), 401

    NONCES[nonce]["used"] = True
    token = secrets.token_urlsafe(32)

    return jsonify({
        "authenticated": True,
        "address": checksum_address,
        "token": token
    }), 200


@app.route("/verify", methods=["POST"])
def verify():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    message = data.get("message")
    signature = data.get("signature")

    if not all([address, message, signature]):
        return jsonify({"valid": False, "error": "Missing required fields"}), 400

    valid = verify_signature(address, message, signature)
    return jsonify({"valid": valid}), 200


